using System;class A{static int[]sx=new int[99],sy=new int[99];static int n,lz0,lz1,lzy;static double Gy(int lx){for(int i=0;i<n-1;i++)if(lx>=sx[i]&&(lx<sx[i+1]||i==n-2))return sy[i]+(double)(sy[i+1]-sy[i])*(lx-sx[i])/(sx[i+1]-sx[i]);return sy[n-1];}static void Main(){n=int.Parse(Console.ReadLine());for(int i=0;i<n;i++){var p=Console.ReadLine().Split(' ');sx[i]=int.Parse(p[0]);sy[i]=int.Parse(p[1]);}for(int i=0;i<n-1;i++)if(sy[i]==sy[i+1]&&sx[i+1]-sx[i]>=1000){lz0=sx[i];lz1=sx[i+1];lzy=sy[i];break;}for(;;){var p=Console.ReadLine().Split(' ');int X=int.Parse(p[0]),Y=int.Parse(p[1]),hs=int.Parse(p[2]),vs=int.Parse(p[3]),fu=int.Parse(p[4]),ro=int.Parse(p[5]),pw=int.Parse(p[6]);double tx=(lz0+lz1)/2.0,dg=Y-Gy(X),df=Y-lzy;int tr=0,tp=0;if(dg<150&&vs<-20){tr=0;tp=4;}else if(Y>300&&(Math.Abs(hs)>25||X<lz0||X>lz1)){if(hs>60)tr=90;else if(hs<-60)tr=-90;else if(X<lz0&&hs<10)tr=-45;else if(X>lz1&&hs>-10)tr=45;else if(Math.Abs(hs)>20)tr=hs>0?30:-30;else tr=X<tx-100?-10:X>tx+100?10:0;tp=4;}else if(df<300&&X>=lz0&&X<=lz1&&Math.Abs(hs)<=25){tr=0;tp=vs<-40?4:vs<-20?3:vs<-10?2:0;}else{tr=Math.Abs(hs)>5?(hs>0?10:-10):X<tx-50?-5:X>tx+50?5:0;tp=tr!=0?4:vs<-35?4:vs>-20?0:3;}int dr=Math.Max(-90,Math.Min(90,tr));dr=Math.Max(ro-15,Math.Min(ro+15,dr));int dp=Math.Max(0,Math.Min(4,tp));dp=Math.Max(pw-1,Math.Min(pw+1,dp));Console.WriteLine($"{dr} {dp}");Console.Out.Flush();}}}